+
+    #[test]
+    fn resource_tracker_pressure_with_zero_limits() {
+        let limits = ResourceLimits::default();
+        let tracker = ResourceTracker::new(limits);
+        // No usage, no limits → pressure = 0
+        assert_eq!(tracker.pressure(), 0.0);
